import { Component, OnInit } from '@angular/core';
import { CommonModule } from '@angular/common';
import { RouterModule } from '@angular/router';
import { FormsModule } from '@angular/forms';
import { TransactionService } from '../../services/transaction.service';
import { AuthService } from '../../services/auth.service';
import { Transaction } from '../../models/transaction.model';

@Component({
  selector: 'app-transactions',
  standalone: true,
  imports: [CommonModule, RouterModule, FormsModule],
  templateUrl: './transactions.component.html',
  styleUrls: ['./transactions.component.css']
})
export class TransactionsComponent implements OnInit {
  transactions: Transaction[] = [];
  filteredTransactions: Transaction[] = [];
  isLoading: boolean = true;
  errorMessage: string = '';
  currentUserId: number = 0;
  currentUserFullName: string = '';

  // Filters
  showFilters: boolean = false;
  searchQuery: string = '';
  selectedYear: string = '';
  selectedMonth: string = '';
  selectedType: string = '';
  availableYears: number[] = [];

  // ✅ Modal state
  showSummaryModal: boolean = false;
  selectedTransaction: Transaction | null = null;

  constructor(
    private transactionService: TransactionService,
    private authService: AuthService
  ) {}

  ngOnInit(): void {
    const currentUser = this.authService.getCurrentUser();
    if (currentUser) {
      this.currentUserId = currentUser.userId ? Number(currentUser.userId) : 0;
      this.currentUserFullName = `${currentUser.firstName} ${currentUser.lastName}`.trim();
    }
    this.loadTransactions();
  }

  loadTransactions(): void {
    this.isLoading = true;
    this.errorMessage = '';

    this.transactionService.getUserTransactions().subscribe({
      next: (response) => {
        this.transactions = Array.isArray(response) ? response : [];
        this.filteredTransactions = [...this.transactions];
        this.buildAvailableYears();
        this.isLoading = false;
      },
      error: (error) => {
        console.error('Error loading transactions:', error);
        this.errorMessage = 'Error loading transactions';
        this.isLoading = false;
      }
    });
  }

  buildAvailableYears(): void {
    const years = this.transactions.map(t =>
      new Date(t.createdAt).getFullYear()
    );
    this.availableYears = [...new Set(years)].sort((a, b) => b - a);
  }

  toggleFilters(): void {
    this.showFilters = !this.showFilters;
  }

  hasActiveFilters(): boolean {
    return !!(this.selectedYear || this.selectedMonth || this.selectedType || this.searchQuery);
  }

  applyFilters(): void {
    const query = this.searchQuery.toLowerCase().trim();

    this.filteredTransactions = this.transactions.filter(transaction => {
      const date = new Date(transaction.createdAt);

      const matchesYear = this.selectedYear
        ? date.getFullYear() === Number(this.selectedYear)
        : true;

      const matchesMonth = this.selectedMonth
        ? date.getMonth() + 1 === Number(this.selectedMonth)
        : true;

      const matchesType = this.selectedType
        ? this.getDirection(transaction) === this.selectedType
        : true;

      const matchesSearch = query
        ? (transaction.fromAccountHolderName?.toLowerCase().includes(query) ||
           transaction.toAccountHolderName?.toLowerCase().includes(query) ||
           transaction.fromAccountNumber?.toLowerCase().includes(query) ||
           transaction.toAccountNumber?.toLowerCase().includes(query) ||
           transaction.referenceNumber?.toLowerCase().includes(query) ||
           transaction.fromBankCode?.toLowerCase().includes(query) ||
           transaction.toBankCode?.toLowerCase().includes(query))
        : true;

      return matchesYear && matchesMonth && matchesType && matchesSearch;
    });
  }

  clearFilters(): void {
    this.searchQuery = '';
    this.selectedYear = '';
    this.selectedMonth = '';
    this.selectedType = '';
    this.filteredTransactions = [...this.transactions];
  }

  // ✅ Modal methods
  openSummary(transaction: Transaction): void {
    this.selectedTransaction = transaction;
    this.showSummaryModal = true;
  }

  closeSummary(): void {
    this.showSummaryModal = false;
    this.selectedTransaction = null;
  }

  shareSummary(): void {
    if (!this.selectedTransaction) return;

    const t = this.selectedTransaction;

    const summaryText = `
  NEXAVAULT - Transaction Receipt
  -----------------------------------------
  Reference ID : ${t.referenceNumber}
  Amount       : ${this.formatCurrency(t.amount)}
  Status       : ${t.status}
  Date         : ${this.formatDate(t.createdAt)}

  From
  ${t.fromAccountHolderName}
  A/C: ${t.fromAccountNumber}

  To
  ${t.toAccountHolderName}
  A/C: ${t.toAccountNumber}

  -----------------------------------------
  Secure Digital Receipt
    `.trim();

    if (navigator.share) {
      navigator.share({
        title: 'Nexavault Transaction Receipt',
        text: summaryText
      }).catch(err => console.log('Share failed:', err));
    } else {
      navigator.clipboard.writeText(summaryText).then(() => {
        alert('Receipt copied to clipboard!');
      });
    }
  }

  downloadSummary(): void {
    if (!this.selectedTransaction) return;

    const summaryHTML = this.generateSummaryHTML(this.selectedTransaction);
    const blob = new Blob([summaryHTML], { type: 'text/html' });
    const url = window.URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `transaction-${this.selectedTransaction.referenceNumber}.html`;
    a.click();
    window.URL.revokeObjectURL(url);
  }

 private generateSummaryHTML(transaction: Transaction): string {
   return `
 <!DOCTYPE html>
 <html>
 <head>
 <meta charset="UTF-8">
 <title>Transaction Summary - ${transaction.referenceNumber}</title>

 <style>
   body {
     font-family: Arial, sans-serif;
     background: #f4f6fb;
     margin: 0;
     padding: 40px;
   }

   .receipt-container {
     max-width: 700px;
     margin: auto;
     background: #ffffff;
     border: 2px solid #7c5cbf;
     border-radius: 12px;
     padding: 40px;
     position: relative;
     overflow: hidden;
   }

   .watermark {
     position: absolute;
     top: 50%;
     left: 50%;
     transform: translate(-50%, -50%) rotate(-30deg);
     font-size: 80px;
     color: rgba(124, 92, 191, 0.08);
     font-weight: bold;
     white-space: nowrap;
     pointer-events: none;
   }

   .logo {
     text-align: center;
     margin-bottom: 30px;
   }

   .logo img {
     width: 180px;
   }

   h1 {
     text-align: center;
     color: #7c5cbf;
     margin-bottom: 30px;
   }

   .summary-box {
     border: 1px solid black;
     border-radius: 8px;
     padding: 20px 25px;
   }

   .row {
     display: flex;
     justify-content: space-between;
     padding: 12px 0;
     border-bottom: 1px solid #f0f0f0;
     font-size: 14px;
   }

   .row:last-child {
     border-bottom: none;
   }

   .label {
     color: black;
   }

   .value {
     font-weight: 600;
     text-align: right;
   }

   .section-title {
     margin-top: 25px;
     margin-bottom: 10px;
     font-weight: bold;
     color: #7c5cbf;
   }

   .footer {
     text-align: center;
     margin-top: 30px;
     font-size: 12px;
     color: #888;
   }
 </style>
 </head>

 <body>

 <div class="receipt-container">

   <div class="watermark">NEXAVAULT</div>

   <div class="logo">
     <img src="data:image/png;base64," alt="Nexavault Logo">
   </div>

   <h1>Transaction Receipt</h1>

   <div class="summary-box">

     <div class="row">
       <span class="label">Reference ID</span>
       <span class="value">${transaction.referenceNumber}</span>
     </div>

     <div class="row">
       <span class="label">Amount</span>
       <span class="value">${this.formatCurrency(transaction.amount)}</span>
     </div>

     <div class="row">
       <span class="label">Date</span>
       <span class="value">${this.formatDate(transaction.createdAt)}</span>
     </div>

     <div class="row">
       <span class="label">Status</span>
       <span class="value">${transaction.status}</span>
     </div>

     <div class="section-title">From</div>
     <div class="row">
       <span class="label">Account Holder</span>
       <span class="value">${transaction.fromAccountHolderName}</span>
     </div>

     <div class="row">
       <span class="label">Account Number</span>
       <span class="value">${transaction.fromAccountNumber}</span>
     </div>

     <div class="section-title">To</div>
     <div class="row">
       <span class="label">Account Holder</span>
       <span class="value">${transaction.toAccountHolderName}</span>
     </div>

     <div class="row">
       <span class="label">Account Number</span>
       <span class="value">${transaction.toAccountNumber}</span>
     </div>

   </div>

   <div class="footer">
     This is a system generated receipt by Nexavault.
   </div>

 </div>

 </body>
 </html>
   `;
 }

  getDirection(transaction: Transaction): 'CREDIT' | 'DEBIT' {
    switch (transaction.transactionType) {
      case 'WITHDRAWAL': return 'DEBIT';
      case 'DEPOSIT':    return 'CREDIT';
      case 'TRANSFER':
        return transaction.fromAccountHolderName === this.currentUserFullName
          ? 'DEBIT' : 'CREDIT';
      default: return 'CREDIT';
    }
  }

  formatCurrency(amount: number): string {
    return new Intl.NumberFormat('en-IN', {
      style: 'currency',
      currency: 'INR'
    }).format(amount);
  }

  formatDate(dateString: string): string {
    return new Date(dateString).toLocaleDateString('en-US', {
      year: 'numeric',
      month: 'short',
      day: 'numeric',
      hour: '2-digit',
      minute: '2-digit'
    });
  }
}
